export default function AboutModal({ onClose }) {
    return (
        <div className="modal-overlay" onClick={onClose}>
            <div className="modal-content" onClick={e => e.stopPropagation()}>
                <button className="modal-close" onClick={onClose}>✕</button>

                <h2>📌 О проекте</h2>
                <p className="subtitle">Информационная система для цифровой трансформации библиотечного обслуживания</p>

                <p>Данный проект представляет собой дипломную работу студентов Колледжа «Царицино». Он разработан для демонстрации возможностей цифровой трансформации библиотечной системы с использованием современных веб-технологий.</p>

                <p>Проект включает в себя три основных компонента: стартовую страницу системы, кабинет библиотекаря для управления библиотечными процессами и личный кабинет читателя для удобного взаимодействия с библиотечным фондом.</p>

                <h3>👨‍🎓 Команда авторов</h3>
                <p>Над проектом работали студенты Колледжа «Царицино»:</p>
                <div className="team-grid">
                    <div className="team-card">
                        <span className="initials">СТ</span>
                        <strong>Стахова Юлия</strong>
                        <span>Страница Пользователя</span>
                    </div>
                    <div className="team-card">
                        <span className="initials">ТВ</span>
                        <strong>Тен Владислав</strong>
                        <span>Страница Библиотекаря</span>
                    </div>
                    <div className="team-card">
                        <span className="initials">КМ</span>
                        <strong>Калинаев Максим</strong>
                        <span>Страница Администратора</span>
                    </div>
                </div>

                <h3>💡 Зачем нужен этот сайт?</h3>
                <div className="goals-section">
                    <div className="goal-header">
                        <span className="rocket">🚀</span>
                        <strong>Для облегчения работы библиотеки</strong>
                    </div>
                    <p>Главная цель проекта — облегчить и автоматизировать работу библиотечного персонала и читателей. Система позволяет:</p>
                    <ul className="goals-list">
                        <li>Упростить каталогизацию и поиск книг</li>
                        <li>Автоматизировать выдачу и возврат изданий</li>
                        <li>Облегчить бронирование книг онлайн</li>
                        <li>Упростить учёт штрафов и задолженностей</li>
                        <li>Сделать библиотечные услуги доступными 24/7</li>
                        <li>Снизить нагрузку на библиотечный персонал</li>
                    </ul>
                </div>

                <h3>🛠️ Технологии</h3>
                <p>Проект реализован с использованием следующих технологий:</p>
                <ul className="tech-list">
                    <li>HTML5, CSS3, JavaScript (ванильный)</li>
                    <li>Адаптивная вёрстка для всех устройств</li>
                    <li>Проектирование реляционной базы данных</li>
                    <li>Модульная архитектура приложения</li>
                </ul>

                <div className="modal-footer">
                    <strong>Колледж «Царицино»</strong>
                    <span>Дипломный проект • 2026</span>
                    <span>Стахова Ю. • Тен В. • Калинаев М.</span>
                </div>

                <button className="btn-close-modal" onClick={onClose}>Закрыть</button>
            </div>
        </div>
    );
}